{"script":"const fs = require('fs');

const filePath = "/Users/orion/Documents/WorkBuddy工作空间/CAD图纸识别/(2审)1#3#楼叠合板A.dwg";
const buffer = fs.readFileSync(filePath);

// DWG 2007 (AC1021) 格式分析
// 尝试找到 DWG 文件中的各种表（Table）定义
// 在 DWG 中，文本通常以 TTF 或 SHX 字体形式存储
// 对于中文字符，如果是 SHX 字体，文本可能以特定的编码存储

// 尝试搜索一些常见的 DWG 文本标记
// AutoCAD 文本对象通常以特定标记开头
// 搜索 "TEXT" 或 "MTEXT" 等标记
const markers = ['TEXT', 'MTEXT', 'Text', 'MText', 'AcDbText', 'AcDbMText'];
for (const marker of markers) {
  const buf = Buffer.from(marker, 'ascii');
  let pos = 0;
  let count = 0;
  while ((pos = buffer.indexOf(buf, pos)) !== -1) {
    count++;
    pos += buf.length;
  }
  if (count > 0) {
    console.log(`"${marker}": ${count} 处`);
  }
}

// 搜索 DWG 句柄编码模式（通常文本对象附近会有句柄信息）
// 搜索可能的中文文本区域 - 寻找连续的 ASCII 可打印字符序列
console.log('\n=== 搜索可读文本区域 ===');
let i = 0;
const textChunks = [];
while (i < buffer.length) {
  // 跳过非文本区域
  if (buffer[i] >= 0x20 && buffer[i] <= 0x7E) {
    let start = i;
    while (i < buffer.length && buffer[i] >= 0x20 && buffer[i] <= 0x7E) {
      i++;
    }
    const chunk = buffer.slice(start, i).toString('ascii');
    if (chunk.length > 4) {
      textChunks.push({ pos: start, text: chunk });
    }
  } else {
    i++;
  }
}

// 过滤出有意义的文本
console.log(`找到 ${textChunks.length} 个 ASCII 文本块`);
const meaningful = textChunks.filter(t => 
  t.text.includes('TABLE') || t.text.includes('BLOCK') || 
  t.text.includes('LAYER') || t.text.includes('STYLE') ||
  t.text.includes('DIMENSION') || t.text.includes('VIEW') ||
  t.text.includes('VPORT') || t.text.includes('APPID')
);

for (const t of meaningful.slice(0, 30)) {
  console.log(`位置 ${t.pos}: ${t.text.substring(0, 80)}`);
}

// 也搜索 DWG 中的 Unicode 文本（可能以 0x00 分隔的 ASCII 区域）
console.log('\n=== 搜索带空格的 ASCII 区域 ===');
i = 0;
const spacedTexts = [];
while (i < buffer.length - 2) {
  // 寻找 ASCII 字符 + 0x00 + ASCII 字符 的模式（UTF-16 编码）
  if (buffer[i] >= 0x20 && buffer[i] <= 0x7E && buffer[i+1] === 0x00 &&
      buffer[i+2] >= 0x20 && buffer[i+2] <= 0x7E) {
    let start = i;
    let end = i;
    while (end < buffer.length - 1 && buffer[end] >= 0x20 && buffer[end] <= 0x7E && buffer[end+1] === 0x00) {
      end += 2;
    }
    if (end > start) {
      const chunk = buffer.slice(start, end);
      // 每隔一个字节取一个
      let text = '';
      for (let j = 0; j < chunk.length; j += 2) {
        text += String.fromCharCode(chunk[j]);
      }
      if (text.length > 3) {
        spacedTexts.push({ pos: start, text });
      }
    }
    i = end || i + 2;
  } else {
    i++;
  }
}

console.log(`找到 ${spacedTexts.length} 个 UTF-16 文本块`);
const meaningful2 = spacedTexts.filter(t => 
  t.text.includes('TABLE') || t.text.includes('表') ||
  t.text.includes('BLOCK') || t.text.includes('构件') ||
  t.text.includes('LAYER') || t.text.includes('叠合')
);

for (const t of meaningful2.slice(0, 30)) {
  console.log(`位置 ${t.pos}: ${t.text.substring(0, 100)}`);
}
"}

{"script":"const fs = require('fs');

const filePath = "/Users/orion/Documents/WorkBuddy工作空间/CAD图纸识别/(2审)1#3#楼叠合板A.dwg";
const buffer = fs.readFileSync(filePath);

// 搜索 UTF-16 文本块中可能包含中文的
let i = 0;
const textBlocks = [];
while (i < buffer.length - 3) {
  // 尝试检测 UTF-16LE 中文（范围 0x4E00-0x9FFF, 0x3400-0x4DBF 等）
  if (i + 1 < buffer.length) {
    const code = buffer[i] | (buffer[i+1] << 8);
    // 检查是否是中文字符范围
    if ((code >= 0x4E00 && code <= 0x9FFF) || 
        (code >= 0x3400 && code <= 0x4DBF) ||
        (code >= 0xF900 && code <= 0xFAFF) ||
        (code >= 0x2F800 && code <= 0x2FA1F)) {
      // 找到了中文字符，尝试提取一段连续的文本
      let start = Math.max(0, i - 20);
      let end = Math.min(buffer.length, i + 60);
      let chunk = buffer.slice(start, end);

      // 尝试解码为 UTF-16LE
      try {
        let text = '';
        for (let j = 0; j < chunk.length; j += 2) {
          if (j + 1 < chunk.length) {
            const c = chunk[j] | (chunk[j+1] << 8);
            if (c >= 0x20 && c <= 0xFFFF) {
              text += String.fromCharCode(c);
            } else {
              text += '?';
            }
          }
        }
        // 过滤出包含有意义中文的文本
        if (/[\u4e00-\u9fff\u3400-\u4dbf]/.test(text) && text.length > 4) {
          textBlocks.push({ pos: start, text });
        }
      } catch(e) {}
      i += 2;
    } else {
      i += 2;
    }
  } else {
    i++;
  }
}

console.log(`找到 ${textBlocks.length} 个可能包含中文的 UTF-16 文本块`);
// 去重并显示
const seen = new Set();
for (const t of textBlocks.slice(0, 100)) {
  // 提取纯中文部分
  const chineseChars = t.text.replace(/[^\u4e00-\u9fff\u3400-\u4dbf\uff00-\uffef]/g, '');
  if (chineseChars.length > 2 && !seen.has(chineseChars)) {
    seen.add(chineseChars);
    console.log(`位置 ${t.pos}: ${t.text.substring(0, 80)}`);
  }
}
"}

