console.log('=== 搜索 GBK 编码的中文文本区域 ===');
let textSegments = [];
let i = 0;
let currentSegment = { start: -1, bytes: [] };

while (i < buffer.length - 1) {
  const b1 = buffer[i];
  const b2 = buffer[i+1];

  // 检查是否是 GBK 中文字符 (首字节 0x81-0xFE, 次字节 0x40-0xFE)
  if (b1 >= 0x81 && b1 <= 0xFE && b2 >= 0x40 && b2 <= 0xFE && b2 !== 0x7F) {
    if (currentSegment.start === -1) {
      currentSegment.start = i;
    }
    currentSegment.bytes.push(b1, b2);
    i += 2;
  } else {
    if (currentSegment.bytes.length >= 4) { // 至少2个中文字符
      currentSegment.end = i;
      textSegments.push(currentSegment);
    }
    currentSegment = { start: -1, bytes: [] };
    i++;
  }
}

