        const c = chunk[i] | (chunk[i+1] << 8);
        if (c >= 0x20 && c <= 0xFFFF) {
          text += String.fromCharCode(c);
        }
      }
    }

    console.log(`\n"${kw}" 位置 ${pos}:`);
