if (xmlEndPos > 0) {
  end = xmlEndPos + 10;
}

const chunk = buffer.slice(start, end);
let text = '';
for (let i = 0; i < chunk.length; i += 2) {
  if (i + 1 < chunk.length) {
    const code = chunk[i] | (chunk[i+1] << 8);
    if (code >= 0x20 && code <= 0xFFFF) {
      text += String.fromCharCode(code);
    }
  }
}
console.log('=== 产品信息区域 ===');
