  // 提取更大范围
  const ctxStart = Math.max(0, p - 100);
  const ctxEnd = Math.min(buffer.length, p + 200);
  const ctxChunk = buffer.slice(ctxStart, ctxEnd);

  let ctxText = '';
  for (let i = 0; i < ctxChunk.length; i += 2) {
    if (i + 1 < ctxChunk.length) {
      const code = ctxChunk[i] | (ctxChunk[i+1] << 8);
      if (code >= 0x20 && code <= 0xFFFF) {
        ctxText += String.fromCharCode(code);
      }
