{"script":"const { execSync } = require('child_process');

const pythonScript = `
filepath = "/Users/orion/Documents/WorkBuddy工作空间/CAD图纸识别/(2审)1#3#楼叠合板A.dwg"

with open(filepath, 'rb') as f:
    data = f.read()

# 提取所有 UTF-16LE 编码的 ASCII 文本区域
print("=== 所有 UTF-16LE ASCII 文本区域 ===\\n")

texts = []
i = 0
while i < len(data) - 3:
    # 检查 UTF-16LE ASCII 字符
    if data[i] >= 0x20 and data[i] <= 0x7E and data[i+1] == 0x00:
        start = i
        text = ''
        while i < len(data) - 1 and data[i] >= 0x20 and data[i] <= 0x7E and data[i+1] == 0x00:
            text += chr(data[i])
            i += 2
        if len(text) >= 4:
            texts.append((start, text))
    else:
        i += 2

print(f"共找到 {len(texts)} 个文本区域\\n")

# 按位置排序并显示
texts.sort(key=lambda x: x[0])
for pos, text in texts:
    print(f"位置 {pos} (0x{pos:x}): {text}")

print("\\n\\n=== 搜索包含中文的 UTF-16LE 文本 ===\\n")

# 搜索包含中文的 UTF-16LE 文本
chinese_texts = []
i = 0
while i < len(data) - 3:
    # 检查是否是中文字符 (CJK Unified Ideographs)
    code = data[i] | (data[i+1] << 8)
    if 0x4E00 <= code <= 0x9FFF or 0x3400 <= code <= 0x4DBF:
        start = i
        chars = []
        while i < len(data) - 1:
            c = data[i] | (data[i+1] << 8)
            if (0x4E00 <= c <= 0x9FFF or 0x3400 <= c <= 0x4DBF or
                0x0020 <= c <= 0x007E or 0xFF00 <= c <= 0xFFEF or
                0x3000 <= c <= 0x303F or c == 0x00A0 or
                0x0030 <= c <= 0x0039):
                chars.append(chr(c))
                i += 2
                if len(chars) > 100:
                    break
            else:
                break
        if len(chars) >= 3:
            text = ''.join(chars)
            # 过滤掉明显是乱码的文本
            chinese_count = sum(1 for c in text if '\u4e00' <= c <= '\u9fff' or '\u3400' <= c <= '\u4dbf')
            if chinese_count >= 2:
                chinese_texts.append((start, text))
    else:
        i += 2

print(f"共找到 {len(chinese_texts)} 个中文文本区域\\n")

# 显示前 100 个
for pos, text in chinese_texts[:100]:
    print(f"位置 {pos} (0x{pos:x}): {text[:120]}")
`;

fs.writeFileSync('/tmp/analyze_dwg3.py', pythonScript);
